t.script:
(function() {
    function getCheckedValue(name) {
        var checked = document.querySelector('input[name="' + name + '"]:checked');
        return checked ? checked.value : '';
    }

    function syncPositionLevelWithSelectedJob() {
        var jobSelect = document.getElementById('portal_job_name_select');
        var mgmtRadio = document.getElementById('level_mgmt');
        var staffRadio = document.getElementById('level_staff');
        if (!jobSelect || !mgmtRadio || !staffRadio) {
            return;
        }

        var selectedOption = jobSelect.options[jobSelect.selectedIndex];
        var selectedLevel = selectedOption ? (selectedOption.dataset.positionLevel || '') : '';

        if (selectedLevel) {
            mgmtRadio.checked = selectedLevel === 'management';
            staffRadio.checked = selectedLevel === 'staff';
            mgmtRadio.disabled = true;
            staffRadio.disabled = true;
        } else {
            mgmtRadio.disabled = false;
            staffRadio.disabled = false;
        }
    }

    function filterPositionOptions() {
        var jobSelect = document.getElementById('portal_job_name_select');
        var deptSelect = document.getElementById('portal_department_select');
        if (!jobSelect || !deptSelect) {
            return;
        }

        var deptVal = deptSelect.value || '';
        var recruitmentType = getCheckedValue('recruitment_type') || 'store';
        var seen = {};
        var hasDeptTemplates = false;

        // Bước 1: Hiện/Ẩn các option theo Department cụ thể
        var deptOptions = jobSelect.querySelectorAll('option[data-template="1"]');
        deptOptions.forEach(function(opt) {
            var sameDept = opt.dataset.departmentId === deptVal;
            var sameType = !recruitmentType || opt.dataset.recruitmentType === recruitmentType;

            if (sameDept && sameType) {
                opt.hidden = false;
                opt.disabled = false;
                seen[opt.value] = true;
                hasDeptTemplates = true;
            } else {
                opt.hidden = true;
                opt.disabled = true;
            }
        });

        // Bước 2: Xử lý Master Options (Chỉ hiện khi Department chưa có template riêng hoặc tên không trùng)
        var masterOptions = jobSelect.querySelectorAll('option[data-master="1"]');
        masterOptions.forEach(function(opt) {
            var key = opt.value;
            // Nếu đã có template thật cho dept này rồi thì ẩn master đi cho gọn,
            // TRỪ KHI dept đó chưa có gì thì hiện master để user chọn.
            if (!hasDeptTemplates && !seen[key]) {
                opt.hidden = false;
                opt.disabled = false;
            } else {
                opt.hidden = true;
                opt.disabled = true;
            }
        });

        if (jobSelect.selectedIndex > 0) {
            var selected = jobSelect.options[jobSelect.selectedIndex];
            if (selected && (selected.hidden || selected.disabled)) {
                jobSelect.value = '';
            }
        }

        syncPositionLevelWithSelectedJob();
    }

    document.addEventListener('change', function(ev) {
        var target = ev.target;
        if (!target) {
            return;
        }
        if (
            target.id === 'portal_department_select' ||
            target.name === 'recruitment_type' ||
            target.id === 'portal_job_name_select'
        ) {
            filterPositionOptions();
        }
    });

    document.addEventListener('DOMContentLoaded', filterPositionOptions);
    filterPositionOptions();
})();

            (function() {
                var fpConfig = {
                    enableTime: true,
                    dateFormat: "d/m/Y h:i K",
                    allowInput: true,
                    time_24hr: false
                };
                var fp1, fp2, fp3;

                document.addEventListener('DOMContentLoaded', function() {
                    fp1 = flatpickr("#interview_date_1", fpConfig);
                    fp2 = flatpickr("#interview_date_2", fpConfig);
                    fp3 = flatpickr("#interview_date_3", fpConfig);

                    // Auto-select first row if exists
                    setTimeout(function() {
                        var firstRow = document.querySelector('.schedule-row');
                        if (firstRow) {
                            selectScheduleFromRow(firstRow);
                        }
                    }, 200);
                });

                // Tính ngày Thứ Hai của tuần chứa ngày d
                function getMondayOf(d) {
                    var day = d.getDay(); // 0=Sun,1=Mon,...,6=Sat
                    var diff = (day === 0) ? -6 : 1 - day;
                    var mon = new Date(d);
                    mon.setDate(d.getDate() + diff);
                    return mon;
                }

                function toYMD(d) {
                    var y = d.getFullYear();
                    var m = String(d.getMonth()+1).padStart(2,'0');
                    var dd = String(d.getDate()).padStart(2,'0');
                    return y+'-'+m+'-'+dd;
                }

                function formatDMY(d) {
                    return String(d.getDate()).padStart(2,'0')+'/'+String(d.getMonth()+1).padStart(2,'0')+'/'+d.getFullYear();
                }

                function parseVNDateTime(str) {
                    if (!str || str === 'False') return null;
                    try {
                        var parts = str.split(' ');
                        if (parts.length < 3) return null;
                        var dParts = parts[0].split('/');
                        var tParts = parts[1].split(':');
                        var ampm = parts[2];
                        var h = parseInt(tParts[0]);
                        if (ampm === 'PM' && h < 12) h += 12;
                        if (ampm === 'AM' && h === 12) h = 0;
                        return new Date(+dParts[2], +dParts[1]-1, +dParts[0], h, parseInt(tParts[1]));
                    } catch(e) { return null; }
                }

                function formatToVN(val) {
                    if (!val || val === 'False') return '';
                    return val; // data attribute already has dd/MM/YYYY hh:mm AM/PM
                }

                function selectScheduleFromRow(btn) {
                    if (!btn) {
                        return;
                    }
                    var scheduleIdInput = document.getElementById('selected_schedule_id');
                    var deptSelect = document.querySelector('select[name="department_id"]');
                    var slot1 = document.getElementById('interview_date_1');
                    var slot2 = document.getElementById('interview_date_2');
                    var slot3 = document.getElementById('interview_date_3');
                    var maxCandidates1 = document.getElementById('max_candidates_slot_1');
                    var maxCandidates2 = document.getElementById('max_candidates_slot_2');
                    var maxCandidates3 = document.getElementById('max_candidates_slot_3');
                    var info = document.getElementById('selected_schedule_info');

                    var sid = btn.getAttribute('data-schedule-id') || '';
                    var deptId = btn.getAttribute('data-department-id') || '';
                    var weekStart = btn.getAttribute('data-week-start') || '';
                    var deptName = btn.getAttribute('data-department-name') || '';
                    var weekText = btn.getAttribute('data-week-text') || weekStart;

                    scheduleIdInput.value = sid;
                    if (deptSelect && deptId) {
                        deptSelect.value = deptId;
                    }
                    if (weekInput && weekStart) {
                        weekInput.value = weekStart;
                        updateWeekRange();
                    }
                    if (slot1) {
                        var val = formatToVN(btn.getAttribute('data-interview-date-1'));
                        slot1.value = val;
                        if (fp1) fp1.setDate(val, false);
                    }
                    if (slot2) {
                        var val = formatToVN(btn.getAttribute('data-interview-date-2'));
                        slot2.value = val;
                        if (fp2) fp2.setDate(val, false);
                    }
                    if (slot3) {
                        var val = formatToVN(btn.getAttribute('data-interview-date-3'));
                        slot3.value = val;
                        if (fp3) fp3.setDate(val, false);
                    }
                    if (maxCandidates1) {
                        maxCandidates1.value = btn.getAttribute('data-max-candidates-1') || '1';
                    }
                    if (maxCandidates2) {
                        maxCandidates2.value = btn.getAttribute('data-max-candidates-2') || '1';
                    }
                    if (maxCandidates3) {
                        maxCandidates3.value = btn.getAttribute('data-max-candidates-3') || '1';
                    }
                    if (info) {
                        info.textContent = 'Đang cập nhật lịch #' + sid + ' - ' + deptName + ' - ' + weekText;
                    }
                }

                var weekInput = document.getElementById('week_start_date');
                var rangeDisplay = document.getElementById('week_range_display');

                function updateWeekRange() {
                    var val = weekInput.value; // YYYY-MM-DD
                    if (!val) { rangeDisplay.textContent = ''; return; }
                    var parts = val.split('-');
                    var mon = new Date(+parts[0], +parts[1]-1, +parts[2]);
                    var sun = new Date(mon);
                    sun.setDate(mon.getDate() + 6);
                    rangeDisplay.textContent = formatDMY(mon) + ' → ' + formatDMY(sun);
                }

                // Set default = Thứ Hai tuần này
                var today = new Date();
                var monday = getMondayOf(today);
                weekInput.value = toYMD(monday);
                updateWeekRange();

                weekInput.addEventListener('change', function() {
                    // Snap về Thứ Hai nếu user chọn ngày khác
                    var parts = weekInput.value.split('-');
                    var chosen = new Date(+parts[0], +parts[1]-1, +parts[2]);
                    var mon = getMondayOf(chosen);
                    weekInput.value = toYMD(mon);
                    updateWeekRange();
                });

                // Validate trước khi submit
                document.getElementById('form_interview_schedule').addEventListener('submit', function(e) {
                    var weekVal = weekInput.value;
                    if (!weekVal) return; // required sẽ bắt

                    var wParts = weekVal.split('-');
                    var monDate = new Date(+wParts[0], +wParts[1]-1, +wParts[2]);
                    var sunDate = new Date(monDate);
                    sunDate.setDate(monDate.getDate() + 6);
                    sunDate.setHours(23, 59, 59);

                    var slotIds = ['interview_date_1','interview_date_2','interview_date_3'];
                    var errors = [];

                    slotIds.forEach(function(id, idx) {
                        var el = document.getElementById(id);
                        if (!el.value) return; // optional
                        var slotDate = parseVNDateTime(el.value);
                        if (!slotDate) {
                             errors.push('Ngày PV ' + (idx+1) + ' sai định dạng (dd/MM/YYYY hh:mm AM/PM)');
                             return;
                        }
                        if (slotDate < monDate || slotDate > sunDate) {
                            errors.push('Ngày PV ' + (idx+1) + ' (' + el.value + ') không nằm trong tuần ' + formatDMY(monDate) + ' – ' + formatDMY(sunDate));
                        }
                    });

                    if (errors.length > 0) {
                        e.preventDefault();
                        var alertDiv = document.getElementById('slot_error_alert');
                        var alertMsg = document.getElementById('slot_error_msg');
                        alertMsg.innerHTML = errors.map(function(e){return '⚠ '+e;}).join('
');
                        alertDiv.style.display = 'block';
                        alertDiv.scrollIntoView({behavior:'smooth'});
                    }
                });

                document.addEventListener('click', function(ev) {
                    var row = ev.target.closest('.schedule-row');
                    if (!row) {
                        return;
                    }
                    if (ev.target.closest('a[href*="/confirm"]')) {
                        return;
                    }
                    ev.preventDefault();
                    selectScheduleFromRow(row);
                    var form = document.getElementById('form_interview_schedule');
                    if (form) {
                        form.scrollIntoView({behavior: 'smooth', block: 'start'});
                    }
                });
            })();
